-- ============================================================================
-- MICHIGAN development_reports seed — REPRODUCIBLE pg_net REFRESH SCRIPT
-- (pattern: docs/illinois-development-reports-seed.sql; run in the Supabase SQL editor)
--
-- Built 2026-07-15: all 360 modeled MI ZIPs (Wayne/Oakland/Macomb/Kent/Washtenaw/
-- Ottawa/Genesee/Shiawassee/Ingham/Livingston/Monroe) cached through the live engine
-- and materialized into app_*. Development depth from FIVE first-party sources wired
-- this pass: the Detroit BSEED trio — detroit-building-permits / detroit-trades-permits
-- (FOUNDER-SPECIFIED trio incl. Trades) / detroit-demolition-permits (freshness-gated
-- FIRST: max issued_date 2026-07-14/-14/-10; native zip_code; NEW arcgis status_const
-- for the no-status issuance ledgers) — plus two corrected-URL retry captures:
-- ann-arbor-energov-permits (Tyler EnerGov behind the city's Public Permit Map;
-- per-record STREAMURL) and independence-twp-construction-permits (the 'Oakland
-- County' retry's real find, honestly scoped to the township its extent covers).
-- GR/Macomb/Kent/Lansing rejected with receipts (docs/source-registry.md "MICHIGAN
-- WIRE PASS" + "MI checkpoint C"). Centroids pinned to zipcodes PyPI v3.0.0;
-- 0 quarantined. INDEX POLICY: substance gate stamps indexable automatically;
-- throttled sitemap (250 newcomers/day) rolls new pages in — no manual flip.
-- ============================================================================
drop table if exists public._mi_zips;
create table public._mi_zips(zip text primary key, lat float8, lng float8);

-- FIRE in waves of ~90 (offset 0/90/180/270; wait ~2.5 min per wave) ----------------
select count(net.http_post(
  'https://qwnnmljucajnexpxdgxr.supabase.co/functions/v1/get-address-report',
  jsonb_build_object('zip', zip, 'lat', lat, 'lng', lng),
  '{}'::jsonb, '{"Content-Type":"application/json"}'::jsonb, 120000)) as fired
from (select * from public._mi_zips order by zip limit 90 offset 0) w;

-- COLLECT after each wave (transient-safe upsert) -----------------------------------
select (j->>'zip'), (j->'home'->>'lat')::float8, (j->'home'->>'lng')::float8, j->'counts', j->'sites',
       coalesce((j->>'paywall')::bool,false),
       'zipcodes PyPI v3.0.0 centroid; get-address-report ZIP mode; Michigan batch 2026-07-15',
       now()
from (
  select distinct on ((content::jsonb->>'zip')) content::jsonb j
  from net._http_response resp
  where resp.status_code = 200 and left(ltrim(resp.content),1)='{'
    and (content::jsonb->>'zip') in (select zip from public._mi_zips)
    and resp.created > now() - interval '30 minutes'
  order by (content::jsonb->>'zip'), resp.created desc
) r
on conflict (zip) do update set home_lat=excluded.home_lat, home_lng=excluded.home_lng,
  counts=excluded.counts, sites=excluded.sites, paywall=excluded.paywall,
  source_vintage=excluded.source_vintage, refreshed_at=excluded.refreshed_at
where jsonb_array_length(excluded.sites) > 0 or jsonb_array_length(public.development_reports.sites) = 0;

-- RE-FIRE stragglers (180s timeout), then re-collect --------------------------------
select count(net.http_post(
  'https://qwnnmljucajnexpxdgxr.supabase.co/functions/v1/get-address-report',
  jsonb_build_object('zip', z.zip, 'lat', z.lat, 'lng', z.lng),
  '{}'::jsonb, '{"Content-Type":"application/json"}'::jsonb, 180000)) as refired
from public._mi_zips z
where not exists (select 1 from public.development_reports dr where dr.zip = z.zip);

-- MATERIALIZE + verify ---------------------------------------------------------------
select public.app_refresh_all();
select (select count(*) from public.development_reports dr join public._mi_zips z on z.zip=dr.zip) as mi_cached,
       (select count(*) from public.app_community_meta m join public._mi_zips z on z.zip=m.zip where m.indexable) as mi_indexable;
